INSERT INTO public.submissions ("email", "audit_type", "school", "submitted_by", "submitted_at", "status", "remarks", "reviewed_by", "reviewed_at", "values_data", "tables_data", "attachments", "version", "forwarded_to_auditor_id", "forwarded_to_auditor_name", "forwarded_to_auditor_email", "forwarded_to_auditor_ids", "forwarded_to_auditor_names", "forwarded_to_auditor_emails", "forwarded_auditor_type", "forwarded_audit_category", "forwarded_at", "auditor_reviewed_by", "auditor_reviewed_by_designation", "auditor_reviewed_by_role", "auditor_reviewed_on", "root_submission_id", "parent_submission_id", "previous_approved_submission_id", "audit_cycle", "report_category", "approved_at", "approved_by_user_id", "approved_by_name", "approved_by_role", "approved_by_designation", "created_from_version", "has_next_cycle", "next_version_id", "academic_year", "administrative_post", "school_group", "submitted_by_details", "forwarded_administrative_posts", "forwarded_to_auditor_posts", "auditor_correction_requested", "correction_requested_for_auditor", "requires_auditor_resubmission", "auditor_correction_message", "auditor_correction_requested_by", "auditor_correction_requested_by_role", "auditor_correction_requested_on", "auditor_resubmitted_at") VALUES ('arvind.kumar@dypiu.ac.in', 'academic', 'SOMCS', 'Dr Arvind Kumar', '2026-07-11 11:18:22.244946', 'AUDITOR_COMPLETED', NULL, NULL, NULL, '{"schoolName": "School of Media & Communication Studies ", "establishmentYear": "2018", "address": "School of Media & Communication Studies, J Block, D Y Patil International University, Akurdi, Pune. ", "directorName": "Dr. Arvind Kumar", "directorEmail": "arvind.kumar@dypiu.ac.in", "ugIntake": "60", "pgIntake": "", "academicCalendar": "Not Available", "bosMeetingsCount": "3", "stakeholderFeedback": "\u2756\\tFaculty Feedback \\n\u25cf\\tMost of the teachers are satisfied with the overall structure of the curriculum. \\n\u25cf\\tCertain courses may be revised by replacing subjects such as Technical Communication Skills with more contemporary, skill-based courses, considering that students are now technologically savvy.\\n\u25cf\\tThe curriculum should place greater emphasis on emerging skills aligned with current technological advancements.\\n\u25cf\\tIncreased focus on evolving industry requirements is essential to ensure that students are industry-ready upon completion of their education.\\n\\n\u2756\\tAlumni Feedback \\n\u25cf\\tMaximum students are satisfied with the nature of the curriculum. \\n\u25cf\\t30% of students said that there has to be more skill based courses to meet the industry needs. \\n\u25cf\\tSome students said, more courses can be offered in the domain of communication management. \\n\\n\u2756\\tEmployers\u2019 Feedback \\n\u25cf\\tGreater emphasis should be placed on practical, hands-on assignments, with a corresponding reduction in excessive theoretical components, to strengthen experiential learning.\\n\u25cf\\tThe curriculum, which is currently largely journalism-centric, should be broadened to support diverse career pathways beyond traditional journalism, enabling students to pursue varied professional roles.\\n\u25cf\\tIntroduction of more industry-oriented practical courses\u2014such as Advanced Excel, Power BI, query languages, technical writing, and data-related tools\u2014would better prepare students for entry into the corporate sector.\\n\u25cf\\tSpecialized pathways may be explored, such as enabling students of Advertising and Public Relations specialisation to engage with sector-specific industries like real estate and allied domains.\\n\u25cf\\tNew courses on Crisis Communication, Risk Management, and reporting on sensitive and confidential issues should be incorporated to enhance professional communication competence and ethical preparedness.\\n\u25cf\\tContinuous evolution and upgradation of the curriculum in line with changing industry requirements is essential to maintain relevance and ensure students remain industry-ready, while also providing ample writing practice to strengthen critical thinking skills.\\n", "feedbackAnalysis": "Feedback from faculty, alumni, and employers indicates overall satisfaction with the curriculum structure, while highlighting the need for strategic enhancement. Faculty members recommend revising select courses by introducing contemporary, skill-based subjects aligned with technological advancements and evolving industry needs. Alumni feedback reflects general satisfaction, though nearly 30% emphasised the inclusion of more skill-oriented and communication management courses. Employers strongly advocated for increased practical exposure, reduced theoretical load, and diversification beyond a journalism-centric approach. They also suggested introducing industry-relevant tools, sector-specific pathways, and courses on crisis communication and risk management. Collectively, the feedback underscores the importance of continuous curriculum upgradation to ensure industry readiness and relevance.", "actionTakenReport": "Based on the comprehensive feedback received from faculty members, alumni, and employers, the Board of Studies has undertaken targeted curriculum enhancements to strengthen industry relevance and skill orientation. In response to suggestions for introducing contemporary, technology-driven skills, a new skill enhancement course titled \u201cUX Writing\u201d has been introduced. This course is designed to equip students with practical competencies in user-centric content creation, digital communication, and interface writing, thereby addressing emerging industry requirements beyond traditional journalism roles.\\nAdditionally, select modules across existing courses have been revised to incorporate greater practical exposure, updated tools, and application-based learning outcomes. Emphasis has been placed on aligning content with current industry practices, improving hands-on assignments, and enhancing employability skills. These revisions aim to reduce excessive theoretical focus while fostering experiential learning and critical thinking. The implemented changes reflect a proactive approach towards continuous curriculum upgradation, ensuring that students are better prepared for diverse career pathways in the evolving media and communication landscape.", "foreignCollaborations": "NA", "nationalCollaborations": "The Film Appreciation Course was organized by the School of Media and Journalism, D Y Patil International University, in collaboration with the ''Film and Television Institute of India''. The collaboration brought together experienced faculty members and film professionals to deliver a structured academic program on cinema studies. It enabled students to benefit from expert-led sessions, interdisciplinary learning, and exposure to contemporary approaches in film appreciation, strengthening the academic and practical understanding of cinema as an art form and medium of communication.\\nhttps://drive.google.com/file/d/1y9Ws8cmtBGot2gLTjhdd4CY_A61ODyM4/view?usp=sharing \\n", "functionalMousCount": "4", "__auditSignOff": {"submittedBy": {"name": "Dr Arvind Kumar", "designation": "Director", "role": "director", "date": "2026-07-11T11:18:21.988Z"}, "approvedBy": {"name": "", "designation": "", "role": "", "date": ""}, "auditedBy": {"name": "Dr Shailesh Ghodke", "designation": "Internal Academic Auditor", "role": "academic-internal-auditor", "date": "2026-07-18T17:48:51.913149083"}}, "auditObservations": "(1) Please revisit all tabs for correctness/appropriateness of document. \\n\\n(2) Please reverify summary links", "auditRecommendations": "School level coordinator to verify the uniformity of documentation before uploading in the portal.", "auditDocumentation": [{"name": "DYPIU_Academic_Audit_Evaluation_SCMS.xlsx", "fileName": "DYPIU_Academic_Audit_Evaluation_SCMS.xlsx", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/a3c936780a67ce84/attachments/4de5b023-d749-4804-a14e-9d91