Proof": [{"name": "Part C - 7 - SoMCS SUMMARY Sheet.pdf", "fileName": "Part C - 7 - SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/52343abc-609f-43f9-9cc5-c985374b121e-Part_C_-_7_-_SoMCS_SUMMARY_Sheet.pdf"}]}], "teacherAwards": [{"Sr No": "1", "Name of the Teacher": "All", "National Awards": "", "International Awards": "", "Link to relevant Proof": [{"name": "Part C - 8 - SoMCS SUMMARY Sheet.pdf", "fileName": "Part C - 8 - SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/c919a31d-d434-4e71-b794-79ac660fa018-Part_C_-_8_-_SoMCS_SUMMARY_Sheet.pdf"}]}], "patentsCopyrights": [{"Sr. No": "1", "Name of Faculty / Student": "NA", "Application No": "", "Title of Patent / Copyright": "", "Date of filing": "", "Date of publication": "", "Date of award": "", "Link to relevant Proof": ""}], "fdpOrganized": [{"Sl. No": "1", "Name of Convener/Coordinator": "All", "Title of seminar/course": "", "Sponsoring Agency": "", "Duration with dates": "", "No. of internal and external participants": "", "Proceedings published Yes/No": "", "Link to relevant Proof": [{"name": "Part C - 9A - SoMCS SUMMARY Sheet.pdf", "fileName": "Part C - 9A - SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/eb5f0d76-5b89-4d71-973b-f51b8a0c562e-Part_C_-_9A_-_SoMCS_SUMMARY_Sheet.pdf"}]}], "fdpAttended": [{"Sl. No": "1", "Name of Faculty": "All", "Title of seminar/course": "", "Sponsoring Agency / organization": "", "Duration with dates": "", "Date": "", "Link to relevant Proof": [{"name": "Part C - 9B- SoMCS SUMMARY Sheet.pdf", "fileName": "Part C - 9B- SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/74b1c0bc-1077-4297-96ae-d9e83b5b1c3c-Part_C_-_9B-_SoMCS_SUMMARY_Sheet.pdf"}]}], "functionalMous": [{"Sr No": "1", "Name of the Organization / Institution / Industry with whom MoU is signed": "All", "Year of signing MoU": "", "Duration of MoU": "", "List the actual activities under each MoU": "", "Link to relevant Proof": [{"name": "Part C - 11 - SoMCS SUMMARY Sheet.pdf", "fileName": "Part C - 11 - SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/0eaffe0a-1de6-4d3b-887a-ae2110329c91-Part_C_-_11_-_SoMCS_SUMMARY_Sheet.pdf"}]}], "swocStrength": [{"Sr No": "1", "Details": "The School of Media and Communication Studies offers a dynamic, industry-aligned curriculum that combines theoretical foundations with practical training across journalism, advertising, public relations, photography, video production and digital media. This multidisciplinary approach ensures that students not only understand the principles of communication but are also well-equipped to apply them in real-world scenarios. The faculty members bring a unique mix of academic insight and hands-on media experience. Their expertise bridges the gap between classroom learning and industry expectations, making students industry-ready upon graduation. Many of them are seasoned professionals with backgrounds in national and international media organizations, enabling them to provide mentorship rooted in actual newsroom and studio practices. The institution boasts state-of-the-art infrastructure that includes fully equipped newsrooms, audio-visual studios, high-end editing suites, camera and lighting equipment and digital multimedia labs. This modern setup allows students to gain practical exposure using the tools and technologies prevalent in the media industry today. Strong industry linkages enhance the student experience through internships, live projects, guest lectures, and placement opportunities. Collaborations with leading media houses, digital agencies and film production companies ensure students remain in sync with evolving industry trends. Pedagogically, the program emphasizes experiential learning. Students engage in participatory, problem-solving activities such as film productions, exhibitions, research symposiums and media critique sessions. These opportunities enhance critical thinking and creativity. Student life is vibrant, with active participation in clubs, campus publications, film screenings etc.  The school promotes a culture of research and innovation. Students are encouraged to undertake research projects, write media analysis papers, and create documentaries on social and cultural issues, thereby sharpening their analytical and storytelling abilities while contributing to academic and public discourse."}], "swocWeaknesses": [{"Sr No": "1", "Details": "Despite the strong industry-aligned curriculum, there is a gap in global engagement. International exposure\u2014whether through exchange programs, foreign faculty interactions, or participation in global conferences\u2014is limited. This restricts students'' ability to understand transnational media trends, cultural nuances in global journalism and evolving practices across international markets.   The school currently maintains a relatively small number of formal collaborations with external academic institutions, media organizations or research bodies. This hampers opportunities for collaborative projects, joint certifications, exchange programs and global internships. Strategic alliances through MoUs can significantly enhance academic and career pathways, offering students greater versatility and credibility in the job market.  While alumni are a powerful resource for mentoring, networking and industry linkage, there appears to be no structured mechanism to leverage their support consistently. Irregular alumni involvement limits avenues for placements, knowledge-sharing, and institutional development. A robust and engaged alumni network can serve as brand ambassadors and contribute to curriculum refinement, workshops, and fundraising.  Given the fast pace of technological innovation in media, there is a risk that some facilities or software may become outdated. Media tools\u2014such as editing software, AR/VR platforms, AI-driven news generation tools, or modern CMS\u2014require regular updates and training. A failure to keep pace with these changes can hinder students\u2019 readiness for contemporary newsroom and production environments.   Though there is encouragement for student-led research, the overall ecosystem does not yet prioritize rigorous academic inquiry at a level that contributes to scholarly media discourse. The lack of published faculty research, funded projects or peer-reviewed journal output limits the institution\u2019s academic stature and intellectual contribution to the field."}], "swocOpportunities": [{"Sr No": "1", "Details": "The media and communication industry is undergoing rapid transformation, opening up significant opportunities for academic institutions. One of the most compelling factors is the growing demand for skilled media professionals across sectors. With the expansion of digital platforms, newsrooms, OTT services and corporate communication departments, the need for trained journalists, content creators, digital marketers and media strategists has never been higher. This surge presents an opportunity for institutions to align their curricula with market demands, thus enhancing graduate employability. Another key opportunity lies in interdisciplinary collaborations. Media studies now intersect with technology, business, psychology, politics and design, creating fertile ground for cross-departmental programs.  The rise of online and hybrid learning models is another transformative opportunity. Our school can leverage digital platforms to deliver blended learning experiences, reaching learners across geographies and demographics.  Furthermore, emerging domains such as digital marketing, content creation, social media management, podcasting, YouTube channels, and vlogging are reshaping how stories are told and consumed. These fields offer immense scope for skill-based training and entrepreneurial development."}], "swocChallenges": [{"Sr No": "1", "Details": "One of the foremost challenges is the rapid pace of technological innovation, with new platforms, tools and audience behaviours emerging frequently.  Another critical concern is job market saturation, particularly in mainstream journalism. With a growing number of graduates and limited high-paying positions, many aspirants face stiff competition and modest career growth.  The spread of misinformation and fake news poses a serious ethical challenge. Lastly, the decline of traditional media formats such as print and linear television has impacted both pedagogy and placements. As audiences shift to digital-first consumption, specializations focused on legacy media may lose relevance unless adapted to new media formats."}], "swocOtherInformation": [{"Sr No": "1", "Details": "In the internal audit few observations were made regarding opening of student chapter, E-Content, FDPs which were duly taken care of."}]}', '[{"name": "SoMCS BOS SUMMARY.pdf", "fileName": "SoMCS BOS SUMMARY.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/46736a5a-2dbb-4311-a4e9-e9b9b386db4f-SoMCS_BOS_SUMMARY.pdf"}, {"name": "Part C - 2 - SoMCS SUMMARY Sheet.pdf", "fileName": "Part C - 2 - SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/b4aeea40-b2d7-4e62-8fc2-3dd118c9bea6-Part_C_-_2_-_SoMCS_SUMMARY_Sheet.pdf"}, {"name": "Part C - 3 - SoMCS SUMMARY Sheet.pdf", "fileName": "Part C - 3 - SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/c4336353-5933-4fee-803c-e67c6a5ec86d-Part_C_-_3_-_SoMCS_SUMMARY_Sheet.pdf"}, {"name": "Part C - 7 - SoMCS SUMMARY Sheet.pdf", "fileName": "Part C - 7 - SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/52343abc-609f-43f9-9cc5-c985374b121e-Part_C_-_7_-_SoMCS_SUMMARY_Sheet.pdf"}, {"name": "Part C - 8 - SoMCS SUMMARY Sheet.pdf", "fileName": "Part C - 8 - SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/c919a31d-d434-4e71-b794-79ac660fa018-Part_C_-_8_-_SoMCS_SUMMARY_Sheet.pdf"}, {"name": "Part C - 9A - SoMCS SUMMARY Sheet.pdf", "fileName": "Part C - 9A - SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/eb5f0d76-5b89-4d71-973b-f51b8a0c562e-Part_C_-_9A_-_SoMCS_SUMMARY_Sheet.pdf"}, {"name": "Part C - 9B- SoMCS SUMMARY Sheet.pdf", "fileName": "Part C - 9B- SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/74b1c0bc-1077-4297-96ae-d9e83b5b1c3c-Part_C_-_9B-_SoMCS_SUMMARY_Sheet.pdf"}, {"name": "Part C - 11 - SoMCS SUMMARY Sheet.pdf", "fileName": "Part C - 11 - SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/0eaffe0a-1de6-4d3b-887a-ae2110329c91-Part_C_-_11_-_SoMCS_SUMMARY_Sheet.pdf"}, {"name": "Part A -2- SoMCS SUMMARY Sheet.pdf", "fileName": "Part A -2- SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/21655662-4ee2-468c-b2fe-d13e5c6e8412-Part_A_-2-_SoMCS_SUMMARY_Sheet.pdf"}, {"name": "Part A -3-1 SoMCS SUMMARY Sheet.pdf", "fileName": "Part A -3-1 SoMCS SUMMARY Sheet.pdf", "url": "https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/bd7f66e8f7af62de/attachments/b46d3fc0-b2c8-46d3-89e8-aaf43578cfc9-Part_A_-3-1_SoMCS_SUMMARY_Sheet.pdf"}, {"name": "Part A -3-2 SoMCS SUMMARY Sheet.pdf", "fileName": "Part A -3-2 SoMC